+            } else .Minus,
+            '*' => if (self.peek() == '*') blk: {
+                _ = self.advance();
+                if (self.peek() == '=') {
+                    _ = self.advance();
+                    break :blk .DoubleStarEqual;
+                }
+                break :blk .DoubleStar;
+            } else if (self.peek() == '=') blk: {
+                _ = self.advance();
+                break :blk .StarEqual;
+            } else .Star,
+            '/' => if (self.peek() == '/') blk: {
+                _ = self.advance();
+                if (self.peek() == '=') {
+                    _ = self.advance();
+                    break :blk .DoubleSlashEqual;
+                }
+                break :blk .DoubleSlash;
+            } else if (self.peek() == '=') blk: {
+                _ = self.advance();
+                break :blk .SlashEqual;
+            } else .Slash,
+            '%' => if (self.peek() == '=') blk: {
+                _ = self.advance();
+                break :blk .PercentEqual;
+            } else .Percent,
+            '=' => if (self.peek() == '=') blk: {
+                _ = self.advance();
+                break :blk .EqualEqual;
+            } else .Equal,
+            '<' => if (self.peek() == '=') blk: {
+                _ = self.advance();
+                break :blk .LessEqual;
+            } else if (self.peek() == '<') blk: {
+                _ = self.advance();
+                if (self.peek() == '=') {
+                    _ = self.advance();
+                    break :blk .LeftShiftEqual;
+                }
+                break :blk .LeftShift;
+            } else .Less,
+            '>' => if (self.peek() == '=') blk: {
+                _ = self.advance();
+                break :blk .GreaterEqual;
+            } else if (self.peek() == '>') blk: {
+                _ = self.advance();
+                if (self.peek() == '=') {
+                    _ = self.advance();
+                    break :blk .RightShiftEqual;
+                }
+                break :blk .RightShift;
+            } else .Greater,
+            '!' => if (self.peek() == '=') blk: {
+                _ = self.advance();
+                break :blk .NotEqual;
+            } else return,
+            '&' => if (self.peek() == '=') blk: {
+                _ = self.advance();
+                break :blk .AmpersandEqual;
+            } else .Ampersand,
+            '|' => if (self.peek() == '=') blk: {
+                _ = self.advance();
+                break :blk .PipeEqual;
+            } else .Pipe,
+            '^' => if (self.peek() == '=') blk: {
+                _ = self.advance();
+                break :blk .CaretEqual;
+            } else .Caret,
+            '~' => .Tilde,
+            '@' => if (self.peek() == '=') blk: {
+                _ = self.advance();
+                break :blk .AtEqual;
+            } else .At,
+            '(' => .LeftParen,
+            ')' => .RightParen,
+            '[' => .LeftBracket,
+            ']' => .RightBracket,
+            '{' => .LeftBrace,
+            '}' => .RightBrace,
+            ',' => .Comma,
+            ':' => if (self.peek() == '=') blk: {
+                _ = self.advance();
+                break :blk .ColonEqual;
