+            ';' => .Semicolon,
+            '.' => if (self.peek() == '.') blk: {
+                _ = self.advance();
+                if (self.peek() == '.') {
+                    _ = self.advance();
+                    break :blk .Ellipsis;
+                }
+                break :blk .Dot;
+            } else .Dot,
+            else => return,
+        };
+
+        try self.tokens.append(.{ .type = tok_type, .lexeme = self.source[self.pos - 1 .. self.pos], .line = start_line, .column = start_col });
+    }
+};

