+            std.debug.print("AssertionError: {any} != null\n", .{a});
+            if (runner.global_result) |result| {
+                result.addFail("assertEqual failed") catch {};
+            }
+            @panic("assertEqual failed");
+        }
+    }
+    if (a_info == .null and b_info == .optional) {
+        if (b == null) {
