+            for (i.else_body) |s| try collectClosureAppends(s, result, allocator);
+        },
+        .for_stmt => |f| {
+            for (f.body) |s| try collectClosureAppends(s, result, allocator);
+        },
+        .while_stmt => |w| {
+            for (w.body) |s| try collectClosureAppends(s, result, allocator);
+        },
+        .try_stmt => |t| {
